[CmdletBinding()]param()
$ErrorActionPreference='Stop';$root=(Resolve-Path (Join-Path $PSScriptRoot '..')).Path;$work=Join-Path ([IO.Path]::GetTempPath()) ('false-guarantees-'+[guid]::NewGuid().ToString('N'));$fails=[Collections.Generic.List[string]]::new()
function Assert($ok,$message){if(-not $ok){$fails.Add($message)}}
function Put($p,$n,$t,$d,$status='ready'){$m=[ordered]@{schemaVersion=1;recordType=$t;status=$status;owner='fixture';updatedAt='2026-07-19T00:00:00Z';applicability=@{productTypes=@('landing-page');surfaces=@('frontend-visible')};sources=@(@{type='user-approval';path='.studio/APPROVED_CONCEPT.md'});data=$d};"<!-- studio-record`n$($m|ConvertTo-Json -Depth 10)`n-->`n# Fixture`nEvidence."|Set-Content (Join-Path $p ('.studio/'+$n))}
function New-Fixture($name,$surfaces=@('frontend-visible')){$p=Join-Path $work $name;New-Item -ItemType Directory -Force (Join-Path $p '.studio')|Out-Null;Put $p 'PROJECT_STATE.md' 'project-state' @{currentState='implementation-planning';productType='landing-page';workflowMode='standard';surfaces=$surfaces;runnable=$true;risks=@();nextRequiredTransition='implementation';activeScope=@('SCOPE-01')};Put $p 'ACTIVE_AND_DEFERRED_SCOPE.md' 'active-scope' @{active=@(@{id='SCOPE-01';title='scope';surfaces=$surfaces;acceptanceCriteria=@('AC-01')});deferred=@();rejected=@()};Put $p 'APPROVED_CONCEPT.md' 'approved-concept' @{conceptId='C1';approval=@{status='approved';approvedAt='2026-07-19T00:00:00Z';approvedBy='user';source='explicit user approval'};approvedModifications=@();rejectedAlternatives=@()} 'approved';Put $p 'TECH_DECISION.md' 'technical-decision' @{selectedOptionId='A';stack=@();alternativesConsidered=@('A');rationale='fixture';tradeoffs=@();approvedDeviations=@()};Put $p 'IMPLEMENTATION_PLAN.md' 'implementation-plan' @{tasks=@(@{id='T1';owner='builder';surfaces=$surfaces;affectedPaths=@('src/a');acceptanceCriteria=@('AC-01');scopeIds=@('SCOPE-01');dependencies=@()});validationCommands=@();approvedExceptions=@();knownDebt=@()};Put $p 'ACCEPTANCE_CRITERIA.md' 'acceptance-criteria' @{criteria=@(@{id='AC-01';behavior='works';surface=$surfaces[0];evidenceTypes=@('source-review');status='ready'})};if($surfaces -contains 'frontend-visible'){Put $p 'DESIGN_SYSTEM.md' 'design-system' @{designThesis='thesis';signatureElement=@{status='active';description='type';reason=''};gridStrategy=@{columnModel='12';containers=@('standard');gutters='24';alignmentAnchors=@('left');breakpoints=@('768');intentionalGridBreaks=@()};compositionMap=@(@{section='hero'});responsivePlan=@{mobile='stack'};tasteResolution=@{appliedRuleIds=@();approvedExceptions=@()}}};if($surfaces -contains 'backend-api'){Put $p 'BACKEND_SPEC.md' 'backend-spec' @{capabilities=@('fixture');routesOrJobs=@('/fixture');validationStrategy='schema';errorStrategy='typed';loggingStrategy='structured';rateLimitStrategy='none';testStrategy='contract'};Put $p 'API_CONTRACT.md' 'api-contract' @{operations=@(@{id='fixture';method='GET';path='/fixture';requestSchema='none';responseSchema='fixture';errorSchema='error';authentication='none';authorization='none';idempotency='n/a';rateLimit='none'})}};$p}
try{$p=New-Fixture 'valid';& (Join-Path $root 'scripts/Test-ImplementationPreflight.ps1') -ProjectRoot $p|Out-Null;Assert (Test-Path (Join-Path $p '.studio/IMPLEMENTATION_PREFLIGHT.json')) 'valid fixture did not pass.';$missing=New-Fixture 'missing';Remove-Item (Join-Path $missing '.studio/IMPLEMENTATION_PLAN.md');try{& (Join-Path $root 'scripts/Test-ImplementationPreflight.ps1') -ProjectRoot $missing|Out-Null;Assert $false 'missing record passed.'}catch{};$backend=New-Fixture 'backend' @('backend-api');& (Join-Path $root 'scripts/Test-ImplementationPreflight.ps1') -ProjectRoot $backend|Out-Null;$route=& (Join-Path $root 'scripts/Resolve-SpecialistPlan.ps1') -ProjectRoot $backend;Assert ($route.selected -notcontains 'frontend-builder' -and $route.selected -notcontains 'browser-qa') 'backend selected visual roles.';& (Join-Path $root 'scripts/context/build_rule_route_index.ps1') -Check|Out-Null}finally{if(Test-Path $work){Remove-Item -LiteralPath $work -Recurse -Force}}
if($fails.Count){$fails|ForEach-Object{Write-Error $_};exit 1};Write-Host 'False-guarantees fixtures passed: schema, parser, routing, state-machine, integration-script; host and browser runtime unverified.'
